  1	import { type FC, type ReactNode, useCallback, useState } from 'react';
  2	import { useModal } from 'src/modules/Providers/modals/ModalHOC/useModal';
  3	
  4	import type { K8sResourceCommon } from '@openshift-console/dynamic-plugin-sdk';
  5	import {
  6	  Alert,
  7	  AlertVariant,
  8	  Button,
  9	  type ButtonProps,
 10	  ButtonVariant,
 11	  Modal,
 12	  ModalVariant,
 13	} from '@patternfly/react-core';
 14	import { useForkliftTranslation } from '@utils/i18n';
 15	
 16	type ModalFormProps = {
 17	  title: ReactNode;
 18	  children: ReactNode;
 19	  onConfirm: () => Promise<K8sResourceCommon>;
 20	  variant?: ModalVariant;
 21	  confirmLabel?: string;
 22	  cancelLabel?: string;
 23	  className?: string;
 24	  confirmVariant?: ButtonVariant;
 25	  isDisabled?: boolean;
 26	  additionalAction?: ButtonProps;
 27	  testId?: string;
 28	};
 29	
 30	const ModalForm: FC<ModalFormProps> = ({
 31	  additionalAction,
 32	  cancelLabel,
 33	  children,
 34	  className,
 35	  confirmLabel,
 36	  confirmVariant,
 37	  isDisabled,
 38	  onConfirm,
 39	  testId,
 40	  title,
 41	  variant = ModalVariant.small,
 42	}) => {
 43	  const { t } = useForkliftTranslation();
 44	  const { toggleModal } = useModal();
 45	  const [isLoading, setIsLoading] = useState(false);
 46	  const [error, setError] = useState<string | null>(null);
 47	
 48	  const handleConfirm = useCallback(async () => {
 49	    setIsLoading(true);
 50	    setError(null);
 51	
 52	    try {
 53	      await onConfirm();
 54	      toggleModal();
 55	    } catch (e) {
 56	      setError((e as Error)?.message ?? e?.toString());
 57	    } finally {
 58	      setIsLoading(false);
 59	    }
 60	  }, [onConfirm, toggleModal]);
 61	
 62	  return (
 63	    <Modal
 64	      variant={variant}
 65	      title={title}
 66	      isOpen
 67	      showClose={false}
 68	      position="top"
 69	      onClose={toggleModal}
 70	      data-testid={testId}
 71	      actions={[
 72	        <Button
 73	          key="confirm"
 74	          variant={confirmVariant ?? ButtonVariant.primary}
 75	          onClick={handleConfirm}
 76	          isLoading={isLoading}
 77	          isDisabled={isLoading || Boolean(error) || isDisabled}
 78	          data-testid="modal-confirm-button"
 79	        >
 80	          {confirmLabel ?? t('Save')}
 81	        </Button>,
 82	        ...(additionalAction
 83	          ? [
 84	              <Button key="secondary" {...additionalAction}>
 85	                {additionalAction?.children}
 86	              </Button>,
 87	            ]
 88	          : []),
 89	        <Button
 90	          key="cancel"
 91	          variant={ButtonVariant.secondary}
 92	          onClick={toggleModal}
 93	          data-testid="modal-cancel-button"
 94	        >
 95	          {cancelLabel ?? t('Cancel')}
 96	        </Button>,
 97	      ]}
 98	      className={className}
 99	    >
100	      {children}
101	
102	      {error && (
103	        <Alert title={t('Error')} variant={AlertVariant.danger} isInline>
104	          {t('{{errorMessage}}', { errorMessage: error })}
105	        </Alert>
106	      )}
107	    </Modal>
108	  );
109	};
110	
111	export default ModalForm;

